import{m as t,aU as a,z as r,M as l}from"./chunks/framework.LN92DB6A.js";const o=JSON.parse('{"title":"2026广州幼升小/小升初入学攻略：报名时间、材料、流程","description":"广州入学季来了，户籍生怎么报名？非户籍生积分入学怎么操作？本文整理2026年最新入学政策和报名全流程。","frontmatter":{"title":"2026广州幼升小/小升初入学攻略：报名时间、材料、流程","tags":["广州","入学","幼升小","小升初","积分入学","学位"],"categories":["教育"],"date":"2026-06-03T00:00:00.000Z","description":"广州入学季来了，户籍生怎么报名？非户籍生积分入学怎么操作？本文整理2026年最新入学政策和报名全流程。","head":[["link",{"rel":"canonical","href":"https://guangzhou.suporka.site/posts/2026/school-enrollment"}]]},"headers":[],"relativePath":"posts/2026/school-enrollment.md","filePath":"posts/2026/school-enrollment.md","lastUpdated":1779868425000}');const i=t({name:"posts/2026/school-enrollment.md"},[["render",function(t,o,i,e,d,s){return a(),r("div",null,[...o[0]||(o[0]=[l('<p>又到一年入学季，家有适龄儿童的家长开始焦虑了——什么时候报名？要准备什么材料？非户籍能不能上公办？政策每年都变，提前搞清楚能少很多焦虑。</p><p>本文帮你理清广州入学的基本规则和流程，不管是户籍生还是非户籍生，都能找到对应的操作路径。</p><h2 id="广州入学政策总览" tabindex="-1">广州入学政策总览 <a class="header-anchor" href="#广州入学政策总览" aria-label="Permalink to &quot;广州入学政策总览&quot;">​</a></h2><h3 id="基本原则" tabindex="-1">基本原则 <a class="header-anchor" href="#基本原则" aria-label="Permalink to &quot;基本原则&quot;">​</a></h3><ul><li><strong>就近入学</strong>：公办学校按地段划分，住在哪就上哪附近的学校</li><li><strong>人户一致优先</strong>：孩子的户口地址和实际居住地址一致的，优先安排</li><li><strong>公民同招</strong>：公办和民办学校同步招生，不能同时被两边录取</li></ul><h3 id="时间节点-参考-以当年公布为准" tabindex="-1">时间节点（参考，以当年公布为准） <a class="header-anchor" href="#时间节点-参考-以当年公布为准" aria-label="Permalink to &quot;时间节点（参考，以当年公布为准）&quot;">​</a></h3><div class="table-container"><table><thead><tr><th>事项</th><th>时间</th></tr></thead><tbody><tr><td>政策公布</td><td>4月-5月</td></tr><tr><td>网上报名</td><td>5月（一般5月上旬开始）</td></tr><tr><td>材料审核</td><td>5月-6月</td></tr><tr><td>录取通知</td><td>6月-7月</td></tr><tr><td>民办摇号</td><td>6月左右</td></tr></tbody></table></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>报名时间窗口一般只有1-2周，错过就要等补录或下一年。关注各区教育局公众号，第一时间获取通知。</p></div><h2 id="户籍生入学" tabindex="-1">户籍生入学 <a class="header-anchor" href="#户籍生入学" aria-label="Permalink to &quot;户籍生入学&quot;">​</a></h2><p>孩子有广州户籍的，走的是地段对口入学。</p><h3 id="报名材料" tabindex="-1">报名材料 <a class="header-anchor" href="#报名材料" aria-label="Permalink to &quot;报名材料&quot;">​</a></h3><ul><li><strong>户口簿</strong>（孩子和父母的）</li><li><strong>房产证</strong>或<strong>购房合同</strong>（证明实际居住地）</li><li><strong>预防接种证</strong>（接种完成证明）</li><li><strong>身份证</strong>（父母双方或监护人）</li></ul><h3 id="网上报名流程" tabindex="-1">网上报名流程 <a class="header-anchor" href="#网上报名流程" aria-label="Permalink to &quot;网上报名流程&quot;">​</a></h3><ol><li>登录**&quot;广州市义务教育学校招生报名系统&quot;**</li><li>选择对应的区和学校类型（公办小学/公办初中）</li><li>填写孩子和家庭信息</li><li>上传材料照片</li><li>提交后等待审核</li><li>按通知到学校交验原件</li></ol><h3 id="人户一致-优先级" tabindex="-1">&quot;人户一致&quot;优先级 <a class="header-anchor" href="#人户一致-优先级" aria-label="Permalink to &quot;&quot;人户一致&quot;优先级&quot;">​</a></h3><p>各区对&quot;人户一致&quot;的认定标准略有不同，但一般要求：</p><ul><li>户口簿上的地址和房产证上的地址一致</li><li>孩子和父母（至少一方）在同一户口簿</li><li>实际居住在该地址</li></ul><p>人户一致的优先级最高。如果人户不一致（比如户口在天河但住在番禺），会被统筹安排到有学位的学校，不一定是地段学校。</p><h2 id="非户籍生积分入学" tabindex="-1">非户籍生积分入学 <a class="header-anchor" href="#非户籍生积分入学" aria-label="Permalink to &quot;非户籍生积分入学&quot;">​</a></h2><p>没有广州户籍的孩子，可以通过<strong>积分入学</strong>的方式申请公办学位。</p><h3 id="基本条件" tabindex="-1">基本条件 <a class="header-anchor" href="#基本条件" aria-label="Permalink to &quot;基本条件&quot;">​</a></h3><ul><li>父母持有广州有效<strong>居住证</strong></li><li>父母在广州有<strong>合法稳定住所</strong>和<strong>合法稳定就业</strong></li><li>父母在广州缴纳<strong>社保</strong>（各区要求不同，一般需要连续缴纳一定月数）</li></ul><h3 id="积分怎么算" tabindex="-1">积分怎么算 <a class="header-anchor" href="#积分怎么算" aria-label="Permalink to &quot;积分怎么算&quot;">​</a></h3><p>各区的积分指标和分值略有不同，常见指标包括：</p><div class="table-container"><table><thead><tr><th>指标</th><th>说明</th></tr></thead><tbody><tr><td>居住证年限</td><td>在广州持有居住证的时间</td></tr><tr><td>社保年限</td><td>在广州缴纳社保的时间</td></tr><tr><td>住房情况</td><td>自有住房或租赁备案</td></tr><tr><td>学历</td><td>父母最高学历</td></tr><tr><td>纳税</td><td>在广州的纳税记录</td></tr><tr><td>志愿服务</td><td>社会服务时长</td></tr></tbody></table></div><h3 id="申请流程" tabindex="-1">申请流程 <a class="header-anchor" href="#申请流程" aria-label="Permalink to &quot;申请流程&quot;">​</a></h3><ol><li>在规定时间内到居住地所在区的<strong>来穗人员服务管理中心</strong>或网上提交积分入学申请</li><li>提交材料：居住证、社保证明、租赁合同/房产证、学历证书等</li><li>等待积分核定和排名</li><li>按积分排名和学位数量录取</li><li>被录取的到学校办理注册</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>积分入学的学位数量有限，不是申请了就能上。积分越高越有保障。各区竞争激烈程度不同，建议提前了解所在区往年录取的最低积分。</p></div><h2 id="幼升小-vs-小升初的区别" tabindex="-1">幼升小 vs 小升初的区别 <a class="header-anchor" href="#幼升小-vs-小升初的区别" aria-label="Permalink to &quot;幼升小 vs 小升初的区别&quot;">​</a></h2><div class="table-container"><table><thead><tr><th>对比项</th><th>幼升小</th><th>小升初</th></tr></thead><tbody><tr><td>报名对象</td><td>年满6周岁的儿童</td><td>小学应届毕业生</td></tr><tr><td>报名系统</td><td>同一个招生系统</td><td>同一个招生系统</td></tr><tr><td>对口方式</td><td>按地段对口</td><td>按地段对口或电脑派位</td></tr><tr><td>民办摇号</td><td>有</td><td>有</td></tr><tr><td>特殊要求</td><td>需要预防接种完成证明</td><td>无特殊要求</td></tr></tbody></table></div><p>小升初部分区采用<strong>电脑派位</strong>（摇号）而不是直接对口，比如越秀区的部分学校。</p><h2 id="民办学校报名" tabindex="-1">民办学校报名 <a class="header-anchor" href="#民办学校报名" aria-label="Permalink to &quot;民办学校报名&quot;">​</a></h2><p>如果公办学校不理想，或者非户籍生积分不够，可以考虑民办学校。</p><h3 id="招生方式" tabindex="-1">招生方式 <a class="header-anchor" href="#招生方式" aria-label="Permalink to &quot;招生方式&quot;">​</a></h3><ul><li><strong>网上报名</strong>：在同一个招生系统中选择民办学校</li><li><strong>摇号录取</strong>：报名人数超过招生计划的，通过电脑摇号录取</li><li><strong>直升</strong>：部分九年一贯制学校有直升名额</li></ul><h3 id="志愿填报" tabindex="-1">志愿填报 <a class="header-anchor" href="#志愿填报" aria-label="Permalink to &quot;志愿填报&quot;">​</a></h3><ul><li>可以填报<strong>1-2所</strong>民办学校（各区规定不同）</li><li>被民办学校录取后，公办学位不再保留</li></ul><h3 id="学费参考" tabindex="-1">学费参考 <a class="header-anchor" href="#学费参考" aria-label="Permalink to &quot;学费参考&quot;">​</a></h3><p>民办学校学费差异较大，从几千到几万元一学期不等。报名前了解清楚学费和其他费用。</p><h2 id="避坑提醒" tabindex="-1">避坑提醒 <a class="header-anchor" href="#避坑提醒" aria-label="Permalink to &quot;避坑提醒&quot;">​</a></h2><ul><li><strong>居住登记和居住证要提前半年准备</strong>：积分入学需要居住证，而居住证需要居住登记满半年。孩子上学前一年就要开始准备</li><li><strong>社保不要断</strong>：积分入学对社保连续缴纳有要求，断缴会影响积分</li><li><strong>房产证和户口簿地址要一致</strong>：人户一致优先级最高，地址不一致会被统筹</li><li><strong>关注各区教育局公众号</strong>：政策变化、报名时间、补录通知等第一时间发布</li><li><strong>不要错过报名时间窗口</strong>：一般只有1-2周，错过很麻烦</li><li><strong>预防接种证提前办好</strong>：幼升小需要提供预防接种完成证明，到社区卫生服务中心办理</li><li><strong>民办学校学费看清楚</strong>：除了学费还有住宿费、餐费、校服费等，算好总成本</li></ul><p>入学是大事，提前一年准备不嫌早。关注政策变化、备齐材料、按时报名，大部分孩子都能顺利入学。</p><blockquote><p>相关阅读：<a href="/posts/2026/residence-permit">广州居住证办理攻略</a> | <a href="/posts/2026/social-security">广州社保查询与办事指南</a></p></blockquote>',43)])])}]]);export{o as __pageData,i as default};
